-- Schema: ops_ut
CREATE SCHEMA IF NOT EXISTS ops_ut;

CREATE OR REPLACE FUNCTION ops_ut.test_module_list()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_count int;
BEGIN
  -- Test indirectly: get_index uses _module_list and renders cards
  -- If _module_list returns modules, get_index will contain agent cards
  SELECT length(ops.get_index()) INTO v_count;
  RETURN NEXT ok(v_count > 100, 'get_index returns substantial HTML (uses _module_list)');
  RETURN NEXT ok(
    ops.get_index() LIKE '%cad%',
    'get_index contains cad module card'
  );
END;
$function$;
COMMENT ON FUNCTION ops_ut.test_module_list() IS 'Test _module_list retourne au moins 1 module';

CREATE OR REPLACE FUNCTION ops_ut.test_module_stats()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  v_html := ops.get_agent('cad');
  RETURN NEXT ok(v_html IS NOT NULL, 'get_agent(cad) returns HTML');
  RETURN NEXT ok(v_html LIKE '%pgv-stat%', 'get_agent contains stat widgets');
  RETURN NEXT ok(v_html LIKE '%Fonctions%', 'get_agent shows function count');
END;
$function$;
COMMENT ON FUNCTION ops_ut.test_module_stats() IS 'Test _module_stats via get_agent qui l''utilise';

CREATE OR REPLACE FUNCTION ops_ut.test_pages_render()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN NEXT ok(length(ops.get_index()) > 0, 'get_index renders HTML');
  RETURN NEXT ok(length(ops.get_messages()) > 0, 'get_messages renders HTML');
  RETURN NEXT ok(length(ops.get_hooks()) > 0, 'get_hooks renders HTML');
  RETURN NEXT ok(length(ops.get_agent('cad')) > 0, 'get_agent renders HTML');

  -- Navigation
  RETURN NEXT ok(ops.brand() = 'Ops', 'brand returns Ops');
  RETURN NEXT ok(
    (ops.nav_items())::text LIKE '%Dashboard%',
    'nav_items contains Dashboard'
  );
END;
$function$;
COMMENT ON FUNCTION ops_ut.test_pages_render() IS 'Test toutes les pages retournent du HTML non-vide';

CREATE OR REPLACE FUNCTION ops_ut.test_recent_events()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  -- The dashboard shows recent events from hook_log and agent_message
  -- We have hook events from this session already
  v_html := ops.get_index();
  RETURN NEXT ok(v_html LIKE '%Activite recente%', 'get_index shows recent events section');
  RETURN NEXT ok(v_html LIKE '%hook%' OR v_html LIKE '%message%', 'timeline contains event badges');
END;
$function$;
COMMENT ON FUNCTION ops_ut.test_recent_events() IS 'Test _recent_events via le dashboard qui affiche la timeline';

